sql:
SELECT education, workclass, AVG(age) AS average_age
FROM individuals
GROUP BY education, workclass;

SELECT MAX(capital_gain) AS max_capital_gain
FROM individuals
WHERE occupation = 'Exec-managerial';

SELECT DISTINCT rt.team_name
FROM individuals i
JOIN research_teams rt ON i.research_team_id = rt.team_id;

SELECT AVG(hours_per_week) AS average_hours_per_week
FROM individuals
WHERE workclass = 'State-gov';

SELECT AVG(age) AS average_age
FROM individuals
WHERE age > 50 AND class = '>50K';

SELECT AVG(age) 
FROM individuals 
WHERE education_num > (SELECT AVG(education_num) FROM individuals);

